import { useState, useEffect } from 'react'

/**
 * Custom Hook: useEntries
 * 
 * This hook manages all localStorage operations for your entries.
 * Think of it like the old JavaScript functions but as a React hook.
 * 
 * It handles:
 * - Reading entries from localStorage
 * - Adding new entries
 * - Deleting entries
 * - Clearing all entries
 * 
 * Hooks always start with "use" prefix (React convention)
 */

const STORAGE_KEY = 'ibd_entries'

// Class definition for creating new entry objects
class SymptomEntry {
  constructor(data) {
    this.id = Date.now().toString() // Unique ID based on timestamp
    this.date = data.date
    this.bloating = parseInt(data.bloating) || 0
    this.pain = parseInt(data.pain) || 0
    this.stress = parseInt(data.stress) || 0
    this.fatigue = parseInt(data.fatigue) || 0
    this.stool = parseInt(data.stool) || 0
    this.dayType = data.dayType || ''
    this.flareStatus = data.flareStatus || ''
    this.bloodMucus = data.bloodMucus || ''
    this.keyFoods = data.keyFoods || ''
    this.notes = data.notes || ''
    this.createdAt = new Date().toISOString()
  }
}

/**
 * Helper functions for localStorage operations
 */

function getEntriesFromStorage() {
  const data = localStorage.getItem(STORAGE_KEY)
  return data ? JSON.parse(data) : []
}

function saveEntriesToStorage(entries) {
  // Keep only last 365 entries
  const entriesToSave = entries.slice(-365)
  localStorage.setItem(STORAGE_KEY, JSON.stringify(entriesToSave))
}

/**
 * Main hook function
 * Returns: object with entries array and functions to modify it
 */
export function useEntries() {
  // State: array of entries currently in memory
  const [entries, setEntries] = useState([])

  // useEffect: Run once when component mounts (loads page)
  // Load entries from localStorage into React state
  useEffect(() => {
    const storedEntries = getEntriesFromStorage()
    setEntries(storedEntries)
  }, []) // Empty dependency array = run only once on mount

  /**
   * Add new entry
   * - Create entry object
   * - Check for duplicate date
   * - Update state and localStorage
   */
  const addEntry = (entryData) => {
    const newEntry = new SymptomEntry(entryData)

    // Check if entry already exists for this date
    const existingIndex = entries.findIndex(e => e.date === newEntry.date)

    let updatedEntries
    if (existingIndex !== -1) {
      // Replace existing entry
      updatedEntries = [...entries]
      updatedEntries[existingIndex] = newEntry
    } else {
      // Add new entry
      updatedEntries = [...entries, newEntry]
    }

    setEntries(updatedEntries)
    saveEntriesToStorage(updatedEntries)
  }

  /**
   * Remove entry by ID
   */
  const removeEntry = (entryId) => {
    const updatedEntries = entries.filter(e => e.id !== entryId)
    setEntries(updatedEntries)
    saveEntriesToStorage(updatedEntries)
  }

  /**
   * Clear all entries
   */
  const clearAll = () => {
    setEntries([])
    localStorage.removeItem(STORAGE_KEY)
  }

  // Return object with state and functions
  return {
    entries,
    addEntry,
    removeEntry,
    clearAll
  }
}

/**
 * Flare Calculations Utility
 * 
 * This file contains all the logic for:
 * - Calculating individual flare risk scores
 * - Analyzing trends over time
 * - Generating warning messages
 */

const FLARE_THRESHOLD = 50
const DAYS_TO_ANALYZE = 7

/**
 * Calculate flare risk score for a single entry (0-100)
 * Based on symptom severity and combination of factors
 */
export function calculateFlareRiskScore(entry) {
  let score = 0

  // Pain score (0-25 points)
  if (entry.pain >= 8) score += 25
  else if (entry.pain >= 6) score += 15
  else if (entry.pain >= 4) score += 8

  // Bloating score (0-20 points)
  if (entry.bloating >= 8) score += 20
  else if (entry.bloating >= 6) score += 12
  else if (entry.bloating >= 4) score += 6

  // Flare status (0-20 points)
  if (entry.flareStatus === 'severe') score += 20
  else if (entry.flareStatus === 'moderate') score += 12
  else if (entry.flareStatus === 'mild') score += 5

  // Blood/Mucus (0-15 points)
  if (entry.bloodMucus === 'both') score += 15
  else if (entry.bloodMucus === 'blood' || entry.bloodMucus === 'mucus') score += 10

  // Fatigue score (0-10 points)
  if (entry.fatigue >= 8) score += 10
  else if (entry.fatigue >= 6) score += 6

  // Stool abnormality (0-10 points)
  if (entry.stool <= 2 || entry.stool >= 6) score += 8
  else if (entry.stool === 3 || entry.stool === 5) score += 4

  return Math.min(score, 100) // Cap at 100
}

/**
 * Analyze trends over last N days
 * Returns object with averages and trend direction
 */
export function analyzeTrends(entries) {
  if (entries.length === 0) return null

  // Get entries from last N days
  const cutoffDate = new Date()
  cutoffDate.setDate(cutoffDate.getDate() - DAYS_TO_ANALYZE)

  const recentEntries = entries.filter(e => new Date(e.date) >= cutoffDate)
  if (recentEntries.length === 0) return null

  // Calculate averages
  const avgPain = recentEntries.reduce((sum, e) => sum + e.pain, 0) / recentEntries.length
  const avgBloating = recentEntries.reduce((sum, e) => sum + e.bloating, 0) / recentEntries.length
  const avgFatigue = recentEntries.reduce((sum, e) => sum + e.fatigue, 0) / recentEntries.length

  // Count flare days
  const flareCount = recentEntries.filter(e => e.flareStatus !== 'none' && e.flareStatus !== '').length

  // Check for blood/mucus
  const bloodPresent = recentEntries.some(e => e.bloodMucus !== 'none' && e.bloodMucus !== '')

  // Calculate trend (increasing/decreasing)
  const latestScores = recentEntries.slice(-3).map(calculateFlareRiskScore)
  const trend = latestScores.length >= 2 && latestScores[latestScores.length - 1] > latestScores[0] 
    ? 'rising' 
    : 'stable'

  return {
    avgPain,
    avgBloating,
    avgFatigue,
    flareCount,
    bloodPresent,
    trend,
    daysAnalyzed: recentEntries.length
  }
}

/**
 * Generate warning message and details
 * Returns null if no warning, or object with message, score, and details
 */
export function getWarningMessage(entries) {
  if (entries.length === 0) return null

  const latestEntry = entries[entries.length - 1]
  const score = calculateFlareRiskScore(latestEntry)
  const trends = analyzeTrends(entries)

  if (score < FLARE_THRESHOLD && (!trends || trends.trend === 'stable')) {
    return null // No warning
  }

  const warnings = []
  const details = []

  // Check for severe symptoms
  if (latestEntry.pain >= 8) {
    warnings.push('High pain levels detected')
    details.push(`• Pain score: ${latestEntry.pain}/10`)
  }

  if (latestEntry.bloating >= 8) {
    warnings.push('Significant bloating')
    details.push(`• Bloating score: ${latestEntry.bloating}/10`)
  }

  if (latestEntry.flareStatus === 'severe' || latestEntry.flareStatus === 'moderate') {
    warnings.push(`${latestEntry.flareStatus.charAt(0).toUpperCase() + latestEntry.flareStatus.slice(1)} flare detected`)
    details.push(`• Flare status: ${latestEntry.flareStatus}`)
  }

  if (latestEntry.bloodMucus !== 'none' && latestEntry.bloodMucus !== '') {
    warnings.push(`Blood/mucus present: ${latestEntry.bloodMucus}`)
    details.push(`• Blood/Mucus: ${latestEntry.bloodMucus}`)
  }

  if (trends) {
    if (trends.trend === 'rising' && score >= 25) {
      warnings.push('Symptoms trending upward')
      details.push(`• Trend: Rising over last ${trends.daysAnalyzed} days`)
    }

    if (trends.flareCount >= 3) {
      warnings.push(`Multiple flare days (${trends.flareCount} in last ${DAYS_TO_ANALYZE} days)`)
      details.push(`• Flare days: ${trends.flareCount}/${trends.daysAnalyzed}`)
    }
  }

  return warnings.length > 0 ? { message: warnings.join(' + '), score, details } : null
}

import { calculateFlareRiskScore } from '../utils/flareCalculations'

/**
 * EntryHistory Component
 * 
 * Displays all entries in a table format with:
 * - Date, Pain, Bloating, Flare Status, Stool, Foods, Notes
 * - Color-coded severity (red/orange/green)
 * - Delete button for each entry
 * - Filtered by date range
 * 
 * Props:
 * - entries: array of entry objects
 * - filterDays: number of days to show (7, 14, 30, 999)
 * - onDeleteEntry: function called when delete button is clicked
 */

function EntryHistory({ entries, filterDays, onDeleteEntry }) {
  /**
   * Filter entries based on date range
   */
  function getFilteredEntries() {
    if (filterDays === 999) {
      // Show all entries
      return entries
    }

    // Calculate cutoff date
    const cutoffDate = new Date()
    cutoffDate.setDate(cutoffDate.getDate() - filterDays)

    // Filter and sort
    return entries.filter(e => new Date(e.date) >= cutoffDate)
  }

  /**
   * Sort entries by date (newest first)
   */
  function getSortedEntries() {
    const filtered = getFilteredEntries()
    return filtered.sort((a, b) => new Date(b.date) - new Date(a.date))
  }

  /**
   * Format date as "20 May"
   */
  function formatDate(dateStr) {
    const date = new Date(dateStr)
    return date.toLocaleDateString('en-GB', { year: 'numeric', month: 'short', day: 'numeric' })
  }

  /**
   * Get CSS class for score severity
   */
  function getScoreClass(score) {
    if (score >= 60) return 'score-high'
    if (score >= 40) return 'score-medium'
    return 'score-low'
  }

  /**
   * Get CSS class for flare badge
   */
  function getFlareClass(status) {
    return `flare-${status || 'none'}`
  }

  /**
   * Truncate text with ellipsis
   */
  function truncateText(text, maxLength = 30) {
    if (!text) return '—'
    return text.length > maxLength ? text.substring(0, maxLength) + '...' : text
  }

  const sortedEntries = getSortedEntries()

  // Empty state
  if (sortedEntries.length === 0) {
    return (
      <div className="empty-state">
        <p>No entries yet. Start tracking by submitting your first check-in above!</p>
      </div>
    )
  }

  return (
    <table className="entries-table">
      <thead>
        <tr>
          <th>Date</th>
          <th>Pain</th>
          <th>Bloating</th>
          <th>Flare</th>
          <th>Stool</th>
          <th>Foods</th>
          <th>Notes</th>
          <th>Action</th>
        </tr>
      </thead>
      <tbody>
        {/* Map through entries and render a table row for each */}
        {sortedEntries.map(entry => {
          const score = calculateFlareRiskScore(entry)
          const scoreClass = getScoreClass(score)
          const flareClass = getFlareClass(entry.flareStatus)

          return (
            <tr key={entry.id}>
              <td>{formatDate(entry.date)}</td>
              <td className={scoreClass}>{entry.pain}/10</td>
              <td className={scoreClass}>{entry.bloating}/10</td>
              <td>
                <span className={flareClass}>
                  {entry.flareStatus || '—'}
                </span>
              </td>
              <td>{entry.stool}/7</td>
              <td title={entry.keyFoods}>
                {truncateText(entry.keyFoods)}
              </td>
              <td title={entry.notes}>
                {truncateText(entry.notes)}
              </td>
              <td>
                <button
                  className="btn-delete"
                  onClick={() => onDeleteEntry(entry.id)}
                >
                  Delete
                </button>
              </td>
            </tr>
          )
        })}
      </tbody>
    </table>
  )
}

export default EntryHistory

import { calculateFlareRiskScore, analyzeTrends } from '../utils/flareCalculations'

/**
 * DashboardSummary Component
 * 
 * Displays summary cards with key statistics:
 * - Average pain and bloating
 * - Current flare status
 * - Number of entries
 * - Trend indicator
 * 
 * Props:
 * - entries: array of entry objects
 */

function DashboardSummary({ entries }) {
  /**
   * Calculate average pain over all entries
   */
  function getAveragePain() {
    if (entries.length === 0) return 0
    const total = entries.reduce((sum, e) => sum + e.pain, 0)
    return (total / entries.length).toFixed(1)
  }

  /**
   * Calculate average bloating over all entries
   */
  function getAverageBloating() {
    if (entries.length === 0) return 0
    const total = entries.reduce((sum, e) => sum + e.bloating, 0)
    return (total / entries.length).toFixed(1)
  }

  /**
   * Get latest flare status
   */
  function getLatestFlareStatus() {
    if (entries.length === 0) return 'None'
    return entries[entries.length - 1].flareStatus || 'None'
  }

  /**
   * Get current trend
   */
  function getTrend() {
    const trends = analyzeTrends(entries)
    if (!trends) return 'stable'
    return trends.trend
  }

  /**
   * Count flare days in past 7 days
   */
  function getRecentFlareDays() {
    if (entries.length === 0) return 0
    const cutoffDate = new Date()
    cutoffDate.setDate(cutoffDate.getDate() - 7)

    return entries
      .filter(e => new Date(e.date) >= cutoffDate)
      .filter(e => e.flareStatus !== 'none' && e.flareStatus !== '')
      .length
  }

  const avgPain = getAveragePain()
  const avgBloating = getAverageBloating()
  const latestFlare = getLatestFlareStatus()
  const trend = getTrend()
  const recentFlares = getRecentFlareDays()

  return (
    <section className="dashboard-summary">
      {/* Summary Card: Average Pain */}
      <div className="summary-card">
        <div className="summary-card-content">
          <h3>Avg Pain</h3>
          <div className="summary-value">{avgPain}</div>
          <p className="summary-label">out of 10</p>
        </div>
      </div>

      {/* Summary Card: Average Bloating */}
      <div className="summary-card">
        <div className="summary-card-content">
          <h3>Avg Bloating</h3>
          <div className="summary-value">{avgBloating}</div>
          <p className="summary-label">out of 10</p>
        </div>
      </div>

      {/* Summary Card: Latest Flare */}
      <div className="summary-card">
        <div className="summary-card-content">
          <h3>Current Flare</h3>
          <div className={`summary-value flare-${latestFlare.toLowerCase()}`}>
            {latestFlare}
          </div>
        </div>
      </div>

      {/* Summary Card: Trend */}
      <div className="summary-card">
        <div className="summary-card-content">
          <h3>Trend (7d)</h3>
          <div className={`summary-value trend-${trend}`}>
            {trend === 'rising' ? '📈 Rising' : '📊 Stable'}
          </div>
        </div>
      </div>

      {/* Summary Card: Flare Days */}
      <div className="summary-card">
        <div className="summary-card-content">
          <h3>Flare Days</h3>
          <div className="summary-value">{recentFlares}</div>
          <p className="summary-label">in past 7 days</p>
        </div>
      </div>

      {/* Summary Card: Total Entries */}
      <div className="summary-card">
        <div className="summary-card-content">
          <h3>Total Entries</h3>
          <div className="summary-value">{entries.length}</div>
          <p className="summary-label">tracked</p>
        </div>
      </div>
    </section>
  )
}

export default DashboardSummary

import { getWarningMessage } from '../utils/flareCalculations'

/**
 * WarningAlert Component
 * 
 * Displays a warning box if flare risk is high
 * Shows:
 * - Risk score (0-100)
 * - Warning message
 * - Detailed breakdown of risk factors
 * 
 * Props:
 * - entries: array of entry objects
 */

function WarningAlert({ entries }) {
  const warning = getWarningMessage(entries)

  // If no warning, don't render anything
  if (!warning) {
    return null
  }

  return (
    <section className="card warning">
      <h2>⚠️ Flare Risk Alert</h2>
      <p>
        Risk Score: <strong>{warning.score}/100</strong> - {warning.message}
      </p>
      <div className="warning-details">
        {warning.details.map((detail, index) => (
          <div key={index}>{detail}</div>
        ))}
      </div>
    </section>
  )
}

export default WarningAlert

